def test_build_image_stats_contains_expected_sections():
    raster = gradient_raster(20, 12)
    report = build_image_stats(raster)
    assert report["dimensions"] == {"width": 20, "height": 12}
    assert "channel_means" in report
    assert "luminance" in report
    assert "histogram" in report
    assert report["exposure"] in {"dark", "bright", "balanced", "underexposed", "overexposed"}

